    [Fact]
    public void OptionalNullablePropertiesUnsetAreNotSet_Works()
    {
        var model = new CardPayments::Element
        {
            Category = CardPayments::Category.CardAuthorization,
            CreatedAt = DateTimeOffset.Parse("2020-01-31T23:59:59Z"),
        };

        Assert.Null(model.CardAuthentication);
        Assert.False(model.RawData.ContainsKey("card_authentication"));
        Assert.Null(model.CardAuthorization);
        Assert.False(model.RawData.ContainsKey("card_authorization"));
        Assert.Null(model.CardAuthorizationExpiration);
        Assert.False(model.RawData.ContainsKey("card_authorization_expiration"));
        Assert.Null(model.CardBalanceInquiry);
        Assert.False(model.RawData.ContainsKey("card_balance_inquiry"));
        Assert.Null(model.CardDecline);
        Assert.False(model.RawData.ContainsKey("card_decline"));
        Assert.Null(model.CardFinancial);
        Assert.False(model.RawData.ContainsKey("card_financial"));
        Assert.Null(model.CardFuelConfirmation);
        Assert.False(model.RawData.ContainsKey("card_fuel_confirmation"));
        Assert.Null(model.CardIncrement);
        Assert.False(model.RawData.ContainsKey("card_increment"));
        Assert.Null(model.CardRefund);
        Assert.False(model.RawData.ContainsKey("card_refund"));
        Assert.Null(model.CardReversal);
        Assert.False(model.RawData.ContainsKey("card_reversal"));
        Assert.Null(model.CardSettlement);
        Assert.False(model.RawData.ContainsKey("card_settlement"));
        Assert.Null(model.CardValidation);
        Assert.False(model.RawData.ContainsKey("card_validation"));
        Assert.Null(model.Other);
        Assert.False(model.RawData.ContainsKey("other"));
    }

