    [Fact]
    public void OptionalNullablePropertiesSetToNullAreSetToNull_Works()
    {
        var model = new CardPayments::Element
        {
            Category = CardPayments::Category.CardAuthorization,
            CreatedAt = DateTimeOffset.Parse("2020-01-31T23:59:59Z"),

            CardAuthentication = null,
            CardAuthorization = null,
            CardAuthorizationExpiration = null,
            CardBalanceInquiry = null,
            CardDecline = null,
            CardFinancial = null,
            CardFuelConfirmation = null,
            CardIncrement = null,
            CardRefund = null,
            CardReversal = null,
            CardSettlement = null,
            CardValidation = null,
            Other = null,
        };

        Assert.Null(model.CardAuthentication);
        Assert.True(model.RawData.ContainsKey("card_authentication"));
        Assert.Null(model.CardAuthorization);
        Assert.True(model.RawData.ContainsKey("card_authorization"));
        Assert.Null(model.CardAuthorizationExpiration);
        Assert.True(model.RawData.ContainsKey("card_authorization_expiration"));
        Assert.Null(model.CardBalanceInquiry);
        Assert.True(model.RawData.ContainsKey("card_balance_inquiry"));
        Assert.Null(model.CardDecline);
        Assert.True(model.RawData.ContainsKey("card_decline"));
        Assert.Null(model.CardFinancial);
        Assert.True(model.RawData.ContainsKey("card_financial"));
        Assert.Null(model.CardFuelConfirmation);
        Assert.True(model.RawData.ContainsKey("card_fuel_confirmation"));
        Assert.Null(model.CardIncrement);
        Assert.True(model.RawData.ContainsKey("card_increment"));
        Assert.Null(model.CardRefund);
        Assert.True(model.RawData.ContainsKey("card_refund"));
        Assert.Null(model.CardReversal);
        Assert.True(model.RawData.ContainsKey("card_reversal"));
        Assert.Null(model.CardSettlement);
        Assert.True(model.RawData.ContainsKey("card_settlement"));
        Assert.Null(model.CardValidation);
        Assert.True(model.RawData.ContainsKey("card_validation"));
        Assert.Null(model.Other);
        Assert.True(model.RawData.ContainsKey("other"));
    }

