public class CategoryTest : TestBase
{
    [Theory]
    [InlineData(CardPayments::Category.CardAuthorization)]
    [InlineData(CardPayments::Category.CardAuthentication)]
    [InlineData(CardPayments::Category.CardBalanceInquiry)]
    [InlineData(CardPayments::Category.CardValidation)]
    [InlineData(CardPayments::Category.CardDecline)]
    [InlineData(CardPayments::Category.CardReversal)]
    [InlineData(CardPayments::Category.CardAuthorizationExpiration)]
    [InlineData(CardPayments::Category.CardIncrement)]
    [InlineData(CardPayments::Category.CardSettlement)]
    [InlineData(CardPayments::Category.CardRefund)]
    [InlineData(CardPayments::Category.CardFuelConfirmation)]
    [InlineData(CardPayments::Category.CardFinancial)]
    [InlineData(CardPayments::Category.Other)]
    public void Validation_Works(CardPayments::Category rawValue)
    {
        // force implicit conversion because Theory can't do that for us
        ApiEnum<string, CardPayments::Category> value = rawValue;
        value.Validate();
    }

    [Fact]
    public void InvalidEnumValidationThrows_Works()
    {
        var value = JsonSerializer.Deserialize<ApiEnum<string, CardPayments::Category>>(
            JsonSerializer.SerializeToElement("invalid value"),
            ModelBase.SerializerOptions
        );

        Assert.NotNull(value);
        Assert.Throws<IncreaseInvalidDataException>(() => value.Validate());
    }

    [Theory]
    [InlineData(CardPayments::Category.CardAuthorization)]
    [InlineData(CardPayments::Category.CardAuthentication)]
    [InlineData(CardPayments::Category.CardBalanceInquiry)]
    [InlineData(CardPayments::Category.CardValidation)]
    [InlineData(CardPayments::Category.CardDecline)]
    [InlineData(CardPayments::Category.CardReversal)]
    [InlineData(CardPayments::Category.CardAuthorizationExpiration)]
    [InlineData(CardPayments::Category.CardIncrement)]
    [InlineData(CardPayments::Category.CardSettlement)]
    [InlineData(CardPayments::Category.CardRefund)]
    [InlineData(CardPayments::Category.CardFuelConfirmation)]
    [InlineData(CardPayments::Category.CardFinancial)]
    [InlineData(CardPayments::Category.Other)]
    public void SerializationRoundtrip_Works(CardPayments::Category rawValue)
    {
        // force implicit conversion because Theory can't do that for us
        ApiEnum<string, CardPayments::Category> value = rawValue;

        string json = JsonSerializer.Serialize(value, ModelBase.SerializerOptions);
        var deserialized = JsonSerializer.Deserialize<ApiEnum<string, CardPayments::Category>>(
            json,
            ModelBase.SerializerOptions
        );

        Assert.Equal(value, deserialized);
    }

    [Fact]
    public void InvalidEnumSerializationRoundtrip_Works()
    {
        var value = JsonSerializer.Deserialize<ApiEnum<string, CardPayments::Category>>(
            JsonSerializer.SerializeToElement("invalid value"),
            ModelBase.SerializerOptions
        );
        string json = JsonSerializer.Serialize(value, ModelBase.SerializerOptions);
        var deserialized = JsonSerializer.Deserialize<ApiEnum<string, CardPayments::Category>>(
            json,
            ModelBase.SerializerOptions
        );

        Assert.Equal(value, deserialized);
    }
}

