                },
            ],
            CreatedAt = DateTimeOffset.Parse("2019-12-27T18:11:19.117Z"),
            OneTimeCode = "one_time_code",
            RealTimeDecisionID = "real_time_decision_id",
            VerificationMethod = CardPayments::VerificationMethod.TextMessage,
            VerificationValue = "verification_value",
        };

        List<CardPayments::Attempt> expectedAttempts =
        [
            new()
            {
                CreatedAt = DateTimeOffset.Parse("2019-12-27T18:11:19.117Z"),
                Outcome = CardPayments::Outcome.Successful,
            },
        ];
        DateTimeOffset expectedCreatedAt = DateTimeOffset.Parse("2019-12-27T18:11:19.117Z");
