        ApiEnum<string, CardPayments::VerificationMethod> expectedVerificationMethod =
            CardPayments::VerificationMethod.TextMessage;
        string expectedVerificationValue = "verification_value";

        Assert.Equal(expectedAttempts.Count, model.Attempts.Count);
        for (int i = 0; i < expectedAttempts.Count; i++)
        {
            Assert.Equal(expectedAttempts[i], model.Attempts[i]);
        }
        Assert.Equal(expectedCreatedAt, model.CreatedAt);
        Assert.Equal(expectedOneTimeCode, model.OneTimeCode);
        Assert.Equal(expectedRealTimeDecisionID, model.RealTimeDecisionID);
        Assert.Equal(expectedVerificationMethod, model.VerificationMethod);
        Assert.Equal(expectedVerificationValue, model.VerificationValue);
    }

